const b = $input.first().json.body;
const {imageUrl, documentId, workspaceId} = b;
if (!imageUrl || !documentId) throw new Error('imageUrl and documentId required');
return [{json: {imageUrl, documentId, workspaceId}}];

const url = $json.imageUrl.replace('localhost:3100', 'app:3000');
const r = await this.helpers.httpRequest({url: url, encoding: 'arraybuffer', headers: {'Accept': 'image/*'}});
return [{json: {...$json, imageData: Buffer.from(r).toString('base64')}}];

const r = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://paddleocr:8090/ocr',
  headers: { 'Content-Type': 'application/json' },
  body: { image_base64: $json.imageData, language: 'en' },
  json: true
});

let ocrText = '';
if (r.text && r.text.trim()) {
  ocrText = r.text;
} else if (r.blocks && Array.isArray(r.blocks)) {
  ocrText = r.blocks.map(b => b.text).join('
');
}

return [{json: {...$json, ocrText: ocrText.trim(), ocrConfidence: r.total_confidence || 0, ocrBlocks: r.total_blocks || 0}}];
